    it('should get specific label by ID', async () => {
      const labelId = 'Label_1';
      const mockLabel = {
        id: labelId,
        name: 'Work',
        type: 'user',
        messageListVisibility: 'show',
        labelListVisibility: 'labelShow',
      };

      mockGmailApi.users.labels.get = jest.fn().mockResolvedValue({
        data: mockLabel,
      });

      const label = await gmailClient.getLabel(labelId);

      expect(mockGmailApi.users.labels.get).toHaveBeenCalledWith({
        userId: 'me',
        id: labelId,
      });
      expect(label).toEqual(mockLabel);
    });

    it('should handle label not found errors', async () => {
      const labelId = 'non-existent-label';
      const notFoundError = {
        code: 404,
        message: 'Label not found',
      };

      mockGmailApi.users.labels.get = jest.fn().mockRejectedValue(notFoundError);

      await expect(gmailClient.getLabel(labelId)).rejects.toMatchObject({
        code: 404,
        message: 'Label not found',
      });
    });

    it('should retry on rate limits when listing labels', async () => {
      const rateLimitError = {
        code: 429,
        message: 'Rate limit exceeded',
      };
      const mockLabels = [{ id: 'INBOX', name: 'INBOX', type: 'system' }];

      // First call fails with rate limit, second succeeds
      mockGmailApi.users.labels.list = jest
        .fn()
        .mockRejectedValueOnce(rateLimitError)
        .mockResolvedValueOnce({ data: { labels: mockLabels } });

      const labels = await gmailClient.listLabels({ retryOnRateLimit: true, maxRetries: 3 });

      expect(labels).toEqual(mockLabels);
      expect(mockGmailApi.users.labels.list).toHaveBeenCalledTimes(2);
    });

    it('should retry on rate limits when getting label', async () => {
      const labelId = 'Label_1';
      const rateLimitError = {
        code: 429,
        message: 'Rate limit exceeded',
      };
      const mockLabel = { id: labelId, name: 'Work', type: 'user' };

      // First call fails with rate limit, second succeeds
      mockGmailApi.users.labels.get = jest
        .fn()
        .mockRejectedValueOnce(rateLimitError)
        .mockResolvedValueOnce({ data: mockLabel });

      const label = await gmailClient.getLabel(labelId, { retryOnRateLimit: true, maxRetries: 3 });

      expect(label).toEqual(mockLabel);
      expect(mockGmailApi.users.labels.get).toHaveBeenCalledTimes(2);
    });
  });

  describe('cleanup', () => {
    it('should cleanup resources on dispose', async () => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };
      gmailClient = new GmailClient(credentials);

      // Dispose should not throw
      await expect(gmailClient.dispose()).resolves.not.toThrow();
    });
  });
});

