  describe('fetchEmailsByThreads - thread-based fetching', () => {
    beforeEach(() => {
      // Add getThread mock to mockGmailClient
      mockGmailClient.getThread = jest.fn() as any;
    });

    it('should fetch all messages from multiple threads efficiently', async () => {
      const threadIds = ['thread1', 'thread2'];

      // Mock thread responses - each thread contains multiple messages
      const mockThread1 = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: createMinimalPayload('sender1@example.com'),
          },
          {
            id: 'msg2',
            threadId: 'thread1',
            labelIds: ['INBOX', 'IMPORTANT'],
            payload: createMinimalPayload('sender1@example.com'),
          },
        ],
      };

      const mockThread2 = {
        id: 'thread2',
        messages: [
          {
            id: 'msg3',
            threadId: 'thread2',
            labelIds: ['INBOX'],
            payload: createMinimalPayload('sender2@example.com'),
          },
        ],
      };

      (mockGmailClient.getThread as jest.Mock)
        .mockResolvedValueOnce(mockThread1)
        .mockResolvedValueOnce(mockThread2);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      // Should make only 2 API calls (one per thread) instead of 3 (one per message)
      expect(mockGmailClient.getThread).toHaveBeenCalledTimes(2);
      expect(mockGmailClient.getThread).toHaveBeenCalledWith('thread1', 'full', {
        retryOnRateLimit: true,
        maxRetries: 3,
      });
      expect(mockGmailClient.getThread).toHaveBeenCalledWith('thread2', 'full', {
        retryOnRateLimit: true,
        maxRetries: 3,
      });

      // Should return all 3 messages from both threads
      expect(result.emails).toHaveLength(3);
      expect(result.totalFetched).toBe(3);
      expect(result.hasMore).toBe(false); // Thread fetching doesn't use pagination
      expect(result.nextPageToken).toBeUndefined();
    });

    it('should include ALL messages in each thread (new + old)', async () => {
      const threadIds = ['thread-with-history'];

      // Simulate a thread with 5 messages (only 1 might be new, but we get all)
      const mockThread = {
        id: 'thread-with-history',
        messages: Array.from({ length: 5 }, (_, i) => ({
          id: `msg${i + 1}`,
          threadId: 'thread-with-history',
          labelIds: i === 0 ? ['INBOX', 'UNREAD'] : ['INBOX'], // First is new
          payload: createMinimalPayload(`sender${i + 1}@example.com`),
        })),
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      expect(result.emails).toHaveLength(5);
      expect(result.emails[0].id).toBe('msg1');
      expect(result.emails[4].id).toBe('msg5');
    });

    it('should parse all messages from threads correctly', async () => {
      const threadIds = ['thread1'];

      const mockThread = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            snippet: 'Test snippet',
            payload: {
              headers: [
                { name: 'From', value: 'Sender <sender@example.com>' },
                { name: 'To', value: 'recipient@example.com' },
                { name: 'Subject', value: 'Test Subject' },
                { name: 'Date', value: 'Mon, 01 Jan 2024 10:00:00 +0000' },
              ],
            },
          },
        ],
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      expect(result.emails).toHaveLength(1);
      const email = result.emails[0];
      expect(email.id).toBe('msg1');
      expect(email.threadId).toBe('thread1');
      expect(email.from?.email).toBe('sender@example.com');
      expect(email.from?.name).toBe('Sender');
      expect(email.subject).toBe('Test Subject');
    });

    it('should handle threads with no messages', async () => {
      const threadIds = ['empty-thread'];

      const mockThread = {
        id: 'empty-thread',
        messages: [],
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      expect(result.emails).toHaveLength(0);
      expect(result.errors).toHaveLength(0);
    });

    it('should handle threads with undefined messages', async () => {
      const threadIds = ['thread-no-messages'];

      const mockThread = {
        id: 'thread-no-messages',
        // messages property not present
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      expect(result.emails).toHaveLength(0);
      expect(result.errors).toHaveLength(0);
    });

    it('should continue on thread fetch errors when continueOnError is true', async () => {
      const threadIds = ['thread1', 'thread2', 'thread3'];

      const mockThread1 = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: createMinimalPayload(),
          },
        ],
      };

      const mockThread3 = {
        id: 'thread3',
        messages: [
          {
            id: 'msg3',
            threadId: 'thread3',
            labelIds: ['INBOX'],
            payload: createMinimalPayload(),
          },
        ],
      };

      // First succeeds, second fails, third succeeds
      (mockGmailClient.getThread as jest.Mock)
        .mockResolvedValueOnce(mockThread1)
        .mockRejectedValueOnce(new Error('Thread not found'))
        .mockResolvedValueOnce(mockThread3);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds, {
        continueOnError: true,
      });

      expect(result.emails).toHaveLength(2); // Only successful threads
      expect(result.emails[0].id).toBe('msg1');
      expect(result.emails[1].id).toBe('msg3');
      expect(result.errors).toHaveLength(1);
      expect(result.errors[0].messageId).toBe('thread2');
      expect(result.errors[0].error).toContain('Failed to fetch thread');
    });

    it('should stop on first error when continueOnError is false', async () => {
      const threadIds = ['thread1', 'thread2'];

      (mockGmailClient.getThread as jest.Mock).mockRejectedValue(new Error('API error'));

      await expect(
        emailFetcher.fetchEmailsByThreads(threadIds, {
          continueOnError: false,
        })
      ).rejects.toThrow('API error');

      expect(mockGmailClient.getThread).toHaveBeenCalledTimes(1); // Stopped after first error
    });

    it('should collect errors from thread message parsing', async () => {
      const threadIds = ['thread1'];

      const mockThread = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: {
              headers: [], // Missing required From header
            },
          },
          {
            id: 'msg2',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: createMinimalPayload(), // Valid message
          },
        ],
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds, {
        continueOnError: true,
      });

      // First message fails to parse, second succeeds
      expect(result.emails).toHaveLength(1);
      expect(result.emails[0].id).toBe('msg2');
      expect(result.errors).toHaveLength(1);
      expect(result.errors[0].messageId).toBe('msg1');
      expect(result.errors[0].error).toContain('Failed to parse message');
    });

    it('should track performance metrics for thread fetching', async () => {
      const threadIds = ['thread1'];

      const mockThread = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: createMinimalPayload(),
          },
        ],
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      expect(result.durationMs).toBeGreaterThanOrEqual(0);
      expect(result.durationMs).toBeLessThan(10000); // Should complete reasonably fast
    });

    it('should respect format option when fetching threads', async () => {
      const threadIds = ['thread1'];

      const mockThread = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: createMinimalPayload(),
          },
        ],
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      await emailFetcher.fetchEmailsByThreads(threadIds, {
        format: 'metadata',
      });

      expect(mockGmailClient.getThread).toHaveBeenCalledWith('thread1', 'metadata', {
        retryOnRateLimit: true,
        maxRetries: 3,
      });
    });
  });

  describe('performance and rate limiting', () => {
    it('should track fetch performance metrics', async () => {
      const mockMessages = [{ id: 'msg1', threadId: 'thread1' }];

      (mockGmailClient.listMessages as jest.Mock).mockResolvedValue({
        messages: mockMessages,
        resultSizeEstimate: 1,
      });

      (mockGmailClient.getMessage as jest.Mock).mockResolvedValue({
        id: 'msg1',
        threadId: 'thread1',
        labelIds: ['INBOX'],
        payload: createMinimalPayload(),
      });

      const result = await emailFetcher.fetchEmails();

      expect(result.durationMs).toBeGreaterThanOrEqual(0);
      expect(result.totalFetched).toBe(1);
    });
  });
});

