  describe('fetchEmailsByThreads - thread-based fetching', () => {
    beforeEach(() => {
      // Add getThread mock to mockGmailClient
      mockGmailClient.getThread = jest.fn() as any;
    });

    it('should fetch all messages from multiple threads efficiently', async () => {
      const threadIds = ['thread1', 'thread2'];

      // Mock thread responses - each thread contains multiple messages
      const mockThread1 = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: createMinimalPayload('sender1@example.com'),
          },
          {
            id: 'msg2',
            threadId: 'thread1',
            labelIds: ['INBOX', 'IMPORTANT'],
            payload: createMinimalPayload('sender1@example.com'),
          },
        ],
      };

      const mockThread2 = {
        id: 'thread2',
        messages: [
          {
            id: 'msg3',
            threadId: 'thread2',
            labelIds: ['INBOX'],
            payload: createMinimalPayload('sender2@example.com'),
          },
        ],
      };

      (mockGmailClient.getThread as jest.Mock)
        .mockResolvedValueOnce(mockThread1)
        .mockResolvedValueOnce(mockThread2);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      // Should make only 2 API calls (one per thread) instead of 3 (one per message)
      expect(mockGmailClient.getThread).toHaveBeenCalledTimes(2);
      expect(mockGmailClient.getThread).toHaveBeenCalledWith('thread1', 'full', {
        retryOnRateLimit: true,
        maxRetries: 3,
      });
      expect(mockGmailClient.getThread).toHaveBeenCalledWith('thread2', 'full', {
        retryOnRateLimit: true,
        maxRetries: 3,
      });

      // Should return all 3 messages from both threads
      expect(result.emails).toHaveLength(3);
      expect(result.totalFetched).toBe(3);
      expect(result.hasMore).toBe(false); // Thread fetching doesn't use pagination
      expect(result.nextPageToken).toBeUndefined();
    });

    it('should include ALL messages in each thread (new + old)', async () => {
      const threadIds = ['thread-with-history'];

      // Simulate a thread with 5 messages (only 1 might be new, but we get all)
      const mockThread = {
        id: 'thread-with-history',
        messages: Array.from({ length: 5 }, (_, i) => ({
          id: `msg${i + 1}`,
          threadId: 'thread-with-history',
          labelIds: i === 0 ? ['INBOX', 'UNREAD'] : ['INBOX'], // First is new
