      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      expect(result.emails).toHaveLength(5);
      expect(result.emails[0].id).toBe('msg1');
      expect(result.emails[4].id).toBe('msg5');
    });

    it('should parse all messages from threads correctly', async () => {
      const threadIds = ['thread1'];

      const mockThread = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            snippet: 'Test snippet',
