      expect(email.threadId).toBe('thread1');
      expect(email.from?.email).toBe('sender@example.com');
      expect(email.from?.name).toBe('Sender');
      expect(email.subject).toBe('Test Subject');
    });

    it('should handle threads with no messages', async () => {
      const threadIds = ['empty-thread'];

      const mockThread = {
        id: 'empty-thread',
        messages: [],
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      expect(result.emails).toHaveLength(0);
      expect(result.errors).toHaveLength(0);
    });

    it('should handle threads with undefined messages', async () => {
      const threadIds = ['thread-no-messages'];

      const mockThread = {
        id: 'thread-no-messages',
        // messages property not present
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      expect(result.emails).toHaveLength(0);
      expect(result.errors).toHaveLength(0);
    });

    it('should continue on thread fetch errors when continueOnError is true', async () => {
      const threadIds = ['thread1', 'thread2', 'thread3'];

      const mockThread1 = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: createMinimalPayload(),
          },
        ],
      };

      const mockThread3 = {
        id: 'thread3',
        messages: [
          {
            id: 'msg3',
            threadId: 'thread3',
            labelIds: ['INBOX'],
            payload: createMinimalPayload(),
          },
        ],
      };

      // First succeeds, second fails, third succeeds
      (mockGmailClient.getThread as jest.Mock)
        .mockResolvedValueOnce(mockThread1)
        .mockRejectedValueOnce(new Error('Thread not found'))
        .mockResolvedValueOnce(mockThread3);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds, {
        continueOnError: true,
