      expect(result.emails).toHaveLength(2); // Only successful threads
      expect(result.emails[0].id).toBe('msg1');
      expect(result.emails[1].id).toBe('msg3');
      expect(result.errors).toHaveLength(1);
      expect(result.errors[0].messageId).toBe('thread2');
      expect(result.errors[0].error).toContain('Failed to fetch thread');
    });

    it('should stop on first error when continueOnError is false', async () => {
      const threadIds = ['thread1', 'thread2'];

      (mockGmailClient.getThread as jest.Mock).mockRejectedValue(new Error('API error'));

      await expect(
        emailFetcher.fetchEmailsByThreads(threadIds, {
          continueOnError: false,
        })
      ).rejects.toThrow('API error');

      expect(mockGmailClient.getThread).toHaveBeenCalledTimes(1); // Stopped after first error
    });

    it('should collect errors from thread message parsing', async () => {
      const threadIds = ['thread1'];

      const mockThread = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: {
              headers: [], // Missing required From header
            },
          },
          {
            id: 'msg2',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: createMinimalPayload(), // Valid message
          },
        ],
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds, {
        continueOnError: true,
      });

      // First message fails to parse, second succeeds
      expect(result.emails).toHaveLength(1);
      expect(result.emails[0].id).toBe('msg2');
      expect(result.errors).toHaveLength(1);
      expect(result.errors[0].messageId).toBe('msg1');
      expect(result.errors[0].error).toContain('Failed to parse message');
    });

    it('should track performance metrics for thread fetching', async () => {
      const threadIds = ['thread1'];

      const mockThread = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
            labelIds: ['INBOX'],
            payload: createMinimalPayload(),
          },
        ],
      };

      (mockGmailClient.getThread as jest.Mock).mockResolvedValue(mockThread);

      const result = await emailFetcher.fetchEmailsByThreads(threadIds);

      expect(result.durationMs).toBeGreaterThanOrEqual(0);
      expect(result.durationMs).toBeLessThan(10000); // Should complete reasonably fast
    });

    it('should respect format option when fetching threads', async () => {
      const threadIds = ['thread1'];

      const mockThread = {
        id: 'thread1',
        messages: [
          {
            id: 'msg1',
            threadId: 'thread1',
