        emailFetcher: mockEmailFetcher,
        repository,
      });

      expect(result.success).toBe(true);
      expect(result.fetchedCount).toBe(0);
      expect(result.persistedCount).toBe(0);
      expect(mockPrisma.$transaction).not.toHaveBeenCalled();
