function createMockEmail(id: string, threadId: string, fromEmail: string, sentDate?: Date): EmailMessage {
  return {
    id,
    threadId,
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'From', value: `Test Sender <${fromEmail}>` },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Subject', value: 'Test Subject' },
        { name: 'Date', value: (sentDate || new Date()).toISOString() },
      ],
      body: {
        data: 'VGVzdCBib2R5IGNvbnRlbnQ=',
        size: 17,
      },
    },
    subject: 'Test Subject',
    from: {
      email: fromEmail,
      name: 'Test Sender',
      raw: `Test Sender <${fromEmail}>`,
    },
    to: [
      {
        email: 'recipient@example.com',
        name: 'Test Recipient',
        raw: 'Test Recipient <recipient@example.com>',
      },
    ],
    date: sentDate || new Date(),
    messageId: `${id}@mail.example.com`,
    bodyPlain: 'Test body content',
    snippet: 'Test snippet',
    sizeEstimate: 1234,
    isProcessed: false,
    processingPriority: 1,
  };
}

