input.new_string:
  it('should use custom --since date if provided', async () => {
    const customSince = new Date('2024-01-01T00:00:00Z');
    const mockEmails: EmailMessage[] = [createMockEmail('msg1', 'thread1', 'test@example.com')];

    // Mock Phase 1: list messages
    mockGmailClient.listMessages.mockResolvedValue({
      messages: [{ id: 'msg1', threadId: 'thread1' }],
      resultSizeEstimate: 1,
    });

    // Mock Phase 2: fetch threads
    mockEmailFetcher.fetchEmailsByThreads.mockResolvedValue({
      emails: mockEmails,
      totalFetched: mockEmails.length,
      hasMore: false,
      errors: [],
      durationMs: 100,
    });

    (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
      return Promise.all(operations.map(() => Promise.resolve()));
    });

    const result = await fetchAndPersistEmails({
      gmailClient: mockGmailClient,
      emailFetcher: mockEmailFetcher,
      repository,
      sinceDate: customSince,
    });

    // Should skip database timestamp query and use custom date
    expect(mockPrisma.gmailMessage.findFirst).not.toHaveBeenCalled();
    expect(mockGmailClient.listMessages).toHaveBeenCalledWith(
      expect.objectContaining({
        q: 'after:2024/01/01',
      }),
      expect.any(Object)
    );
    expect(result.sinceTimestamp).toEqual(customSince);
  });

  it('should deduplicate threads when multiple messages from same thread', async () => {
    const lastTimestamp = new Date('2024-01-15T10:00:00Z');
    // 3 new messages but only 2 unique threads
    const mockEmails: EmailMessage[] = [
      createMockEmail('msg1', 'thread1', 'test1@example.com'),
      createMockEmail('msg2', 'thread1', 'test2@example.com'), // Same thread as msg1
      createMockEmail('msg3', 'thread2', 'test3@example.com'),
    ];

    (mockPrisma.gmailMessage.findFirst as jest.Mock).mockResolvedValue({
      sentAt: lastTimestamp,
    });

    // Mock list showing 3 messages in 2 threads
    mockGmailClient.listMessages.mockResolvedValue({
      messages: [
        { id: 'msg1', threadId: 'thread1' },
        { id: 'msg2', threadId: 'thread1' }, // Duplicate thread
        { id: 'msg3', threadId: 'thread2' },
      ],
      resultSizeEstimate: 3,
    });

    mockEmailFetcher.fetchEmailsByThreads.mockResolvedValue({
      emails: mockEmails,
      totalFetched: mockEmails.length,
      hasMore: false,
      errors: [],
      durationMs: 100,
    });

    (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
      return Promise.all(operations.map(() => Promise.resolve()));
    });

    const result = await fetchAndPersistEmails({
      gmailClient: mockGmailClient,
      emailFetcher: mockEmailFetcher,
      repository,
    });

    // Should fetch only 2 unique threads, not 3
    expect(mockEmailFetcher.fetchEmailsByThreads).toHaveBeenCalledWith(
      ['thread1', 'thread2'], // Only 2 unique threads
      expect.any(Object)
    );

    expect(result.threadsAffected).toBe(2);
    expect(result.fetchedCount).toBe(3); // 3 new messages
    expect(result.persistedCount).toBe(3); // All 3 persisted
  });

  it('should track new vs updated messages separately', async () => {
    const lastTimestamp = new Date('2024-01-15T10:00:00Z');
    // 1 new message in thread1, but thread1 has 3 total messages (2 old)
    const allThreadMessages: EmailMessage[] = [
      createMockEmail('msg1-old', 'thread1', 'test1@example.com', new Date('2024-01-14T10:00:00Z')),
      createMockEmail('msg2-old', 'thread1', 'test2@example.com', new Date('2024-01-14T11:00:00Z')),
      createMockEmail('msg3-new', 'thread1', 'test3@example.com', new Date('2024-01-15T11:00:00Z')),
    ];

    (mockPrisma.gmailMessage.findFirst as jest.Mock).mockResolvedValue({
      sentAt: lastTimestamp,
    });

    // Mock list showing only 1 new message
    mockGmailClient.listMessages.mockResolvedValue({
      messages: [{ id: 'msg3-new', threadId: 'thread1' }],
      resultSizeEstimate: 1,
    });

    // Mock thread fetch returning ALL messages in thread (new + old)
    mockEmailFetcher.fetchEmailsByThreads.mockResolvedValue({
      emails: allThreadMessages,
      totalFetched: allThreadMessages.length,
      hasMore: false,
      errors: [],
      durationMs: 100,
    });

    (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
      return Promise.all(operations.map(() => Promise.resolve()));
    });

    const result = await fetchAndPersistEmails({
      gmailClient: mockGmailClient,
      emailFetcher: mockEmailFetcher,
      repository,
    });

    expect(result.fetchedCount).toBe(1); // Only 1 NEW message
    expect(result.persistedCount).toBe(3); // All 3 messages persisted (new + updated old)
    expect(result.threadsAffected).toBe(1);
  });

  it('should handle pagination through large message lists', async () => {
    const lastTimestamp = new Date('2024-01-15T10:00:00Z');

    (mockPrisma.gmailMessage.findFirst as jest.Mock).mockResolvedValue({
      sentAt: lastTimestamp,
    });

    // Mock list with pagination (2 pages)
    mockGmailClient.listMessages
      .mockResolvedValueOnce({
        messages: [
          { id: 'msg1', threadId: 'thread1' },
          { id: 'msg2', threadId: 'thread2' },
        ],
        nextPageToken: 'page2token',
        resultSizeEstimate: 4,
      })
      .mockResolvedValueOnce({
        messages: [
          { id: 'msg3', threadId: 'thread3' },
          { id: 'msg4', threadId: 'thread4' },
        ],
        resultSizeEstimate: 4,
      });

    const mockEmails: EmailMessage[] = Array.from({ length: 4 }, (_, i) =>
      createMockEmail(`msg${i + 1}`, `thread${i + 1}`, `test${i + 1}@example.com`)
    );

    mockEmailFetcher.fetchEmailsByThreads.mockResolvedValue({
      emails: mockEmails,
      totalFetched: mockEmails.length,
      hasMore: false,
      errors: [],
      durationMs: 200,
    });

    (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
      return Promise.all(operations.map(() => Promise.resolve()));
    });

    const result = await fetchAndPersistEmails({
      gmailClient: mockGmailClient,
      emailFetcher: mockEmailFetcher,
      repository,
    });

    // Should call listMessages twice (pagination)
    expect(mockGmailClient.listMessages).toHaveBeenCalledTimes(2);

    // Second call should include pageToken
    expect(mockGmailClient.listMessages).toHaveBeenNthCalledWith(
      2,
      expect.objectContaining({
        pageToken: 'page2token',
      }),
      expect.any(Object)
    );

    expect(result.fetchedCount).toBe(4);
    expect(result.threadsAffected).toBe(4);
  });
});

