/**
 * Unit tests for EmailRepository (T042) - Prisma Implementation
 *
 * Test-driven development approach for email persistence layer with batch operations.
 * Tests cover: batch upsert, batch update, query operations, transaction handling.
 */

import { PrismaClient } from '@prisma/client';
import { EmailMessage, EmailAddress } from '@gmail-automation/classification-engine';
import { EmailRepository } from '../../src/persistence/email-repository';

// Mock PrismaClient
jest.mock('@prisma/client', () => {
  const mockPrismaClient = {
    gmailMessage: {
      upsert: jest.fn(),
      update: jest.fn(),
      updateMany: jest.fn(),
      findFirst: jest.fn(),
      findMany: jest.fn(),
    },
    $transaction: jest.fn(),
    $disconnect: jest.fn(),
  };

  return {
    PrismaClient: jest.fn(() => mockPrismaClient),
    Prisma: {
      JsonObject: {},
      JsonArray: [],
    },
  };
});

describe('EmailRepository - Prisma Implementation', () => {
  let repository: EmailRepository;
  let mockPrisma: jest.Mocked<PrismaClient>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Get the mocked Prisma instance
    mockPrisma = new PrismaClient() as jest.Mocked<PrismaClient>;
    repository = new EmailRepository(mockPrisma);
  });

  afterEach(async () => {
    await repository.close();
  });

  describe('constructor', () => {
    it('should create repository with provided Prisma client', () => {
      expect(repository).toBeInstanceOf(EmailRepository);
    });

    it('should create repository with default Prisma client if none provided', () => {
      const defaultRepo = new EmailRepository();
      expect(defaultRepo).toBeInstanceOf(EmailRepository);
    });
  });

  describe('batchInsert', () => {
    it('should upsert multiple emails in a single transaction', async () => {
      const emails: EmailMessage[] = [
        createMockEmail('msg1', 'thread1', 'test1@example.com'),
        createMockEmail('msg2', 'thread2', 'test2@example.com'),
      ];

      // Mock transaction to execute all operations
      (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
        return Promise.all(operations.map(() => Promise.resolve()));
      });

      await repository.batchInsert(emails);

      // Verify transaction was called once
      expect(mockPrisma.$transaction).toHaveBeenCalledTimes(1);
      // Verify it was called with an array of operations
      const call = (mockPrisma.$transaction as jest.Mock).mock.calls[0][0];
      expect(Array.isArray(call)).toBe(true);
      expect(call.length).toBe(2);
    });

    it('should handle empty email array gracefully', async () => {
      await repository.batchInsert([]);

      // Should not attempt transaction
      expect(mockPrisma.$transaction).not.toHaveBeenCalled();
    });

    it('should throw error on transaction failure', async () => {
      const emails: EmailMessage[] = [createMockEmail('msg1', 'thread1', 'test@example.com')];

      (mockPrisma.$transaction as jest.Mock).mockRejectedValue(new Error('Database error'));

      await expect(repository.batchInsert(emails)).rejects.toThrow('Failed to batch insert 1 emails');
    });
  });

  describe('batchUpdateMetadata', () => {
    it('should update processing metadata for multiple emails', async () => {
      const updates = [
        { gmailId: 'msg1', isProcessed: true, processedAt: new Date() },
        { gmailId: 'msg2', isProcessed: true, processedAt: new Date() },
      ];

      (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
        return Promise.all(operations.map(() => Promise.resolve()));
      });

      await repository.batchUpdateMetadata(updates);

      expect(mockPrisma.$transaction).toHaveBeenCalledTimes(1);
    });

    it('should handle empty updates array gracefully', async () => {
      await repository.batchUpdateMetadata([]);

      expect(mockPrisma.$transaction).not.toHaveBeenCalled();
    });
  });

  describe('upsert', () => {
    it('should upsert single email', async () => {
      const email = createMockEmail('msg1', 'thread1', 'test@example.com');

      (mockPrisma.gmailMessage.upsert as jest.Mock).mockResolvedValue({});

      await repository.upsert(email);

      expect(mockPrisma.gmailMessage.upsert).toHaveBeenCalledWith({
        where: { gmailId: email.id },
        create: expect.objectContaining({
          gmailId: email.id,
          gmailThreadId: email.threadId,
          subject: email.subject,
        }),
        update: expect.objectContaining({
          gmailId: email.id,
          gmailThreadId: email.threadId,
          subject: email.subject,
        }),
      });
    });

    it('should throw error on upsert failure', async () => {
      const email = createMockEmail('msg1', 'thread1', 'test@example.com');

      (mockPrisma.gmailMessage.upsert as jest.Mock).mockRejectedValue(new Error('Unique constraint violation'));

      await expect(repository.upsert(email)).rejects.toThrow('Failed to upsert email msg1');
    });
  });

  describe('getLastEmailTimestamp', () => {
    it('should return the most recent email timestamp', async () => {
      const expectedDate = new Date('2024-01-15T10:30:00Z');

      (mockPrisma.gmailMessage.findFirst as jest.Mock).mockResolvedValue({
        sentAt: expectedDate,
      });

      const result = await repository.getLastEmailTimestamp();

      expect(result).toEqual(expectedDate);
      expect(mockPrisma.gmailMessage.findFirst).toHaveBeenCalledWith({
        orderBy: { sentAt: 'desc' },
        select: { sentAt: true },
      });
    });

    it('should return null if no emails exist', async () => {
      (mockPrisma.gmailMessage.findFirst as jest.Mock).mockResolvedValue(null);

      const result = await repository.getLastEmailTimestamp();

      expect(result).toBeNull();
    });
  });

  describe('markAsProcessed', () => {
    it('should mark multiple emails as processed', async () => {
      const gmailIds = ['msg1', 'msg2', 'msg3'];
      const processingBatch = 'batch-123';

      (mockPrisma.gmailMessage.updateMany as jest.Mock).mockResolvedValue({ count: 3 });

      await repository.markAsProcessed(gmailIds, processingBatch);

      expect(mockPrisma.gmailMessage.updateMany).toHaveBeenCalledWith({
        where: { gmailId: { in: gmailIds } },
        data: {
          isProcessed: true,
          processedAt: expect.any(Date),
          processingBatch,
        },
      });
    });

    it('should handle empty gmailIds array gracefully', async () => {
      await repository.markAsProcessed([], 'batch-123');

      expect(mockPrisma.gmailMessage.updateMany).not.toHaveBeenCalled();
    });
  });

  describe('findUnprocessed', () => {
    it('should return unprocessed emails with default limit', async () => {
      const mockDbRows = [
        {
          gmailId: 'msg1',
          gmailThreadId: 'thread1',
          labelIds: ['INBOX'],
          subject: 'Test 1',
          sentAt: new Date(),
          messageIdHdr: null,
          fromSimple: { email: 'test1@example.com', raw: 'test1@example.com' },
          toAddrs: [{ email: 'recipient@example.com', raw: 'recipient@example.com' }],
          replyToAddrs: null,
          headers: [],
          bodyText: null,
          bodyHtml: null,
          bodyTextAsHtml: null,
          raw: { payload: {}, snippet: 'Test snippet' },
          sizeEstimate: null,
          processingBatch: null,
          processingPriority: 1,
          isProcessed: false,
          processedAt: null,
          createdAt: new Date(),
        },
      ];

      (mockPrisma.gmailMessage.findMany as jest.Mock).mockResolvedValue(mockDbRows);

      const result = await repository.findUnprocessed();

      expect(result).toHaveLength(1);
      expect(result[0].id).toBe('msg1');
      expect(mockPrisma.gmailMessage.findMany).toHaveBeenCalledWith({
        where: { isProcessed: false },
        orderBy: { sentAt: 'desc' },
        take: 100,
      });
    });

    it('should respect custom limit parameter', async () => {
      (mockPrisma.gmailMessage.findMany as jest.Mock).mockResolvedValue([]);

      await repository.findUnprocessed({ limit: 50 });

      expect(mockPrisma.gmailMessage.findMany).toHaveBeenCalledWith({
        where: { isProcessed: false },
        orderBy: { sentAt: 'desc' },
        take: 50,
      });
    });

    it('should filter by date range if provided', async () => {
      const startDate = new Date('2024-01-01');
      const endDate = new Date('2024-01-31');

      (mockPrisma.gmailMessage.findMany as jest.Mock).mockResolvedValue([]);

      await repository.findUnprocessed({ startDate, endDate, limit: 100 });

      expect(mockPrisma.gmailMessage.findMany).toHaveBeenCalledWith({
        where: {
          isProcessed: false,
          sentAt: { gte: startDate, lte: endDate },
        },
        orderBy: { sentAt: 'desc' },
        take: 100,
      });
    });
  });

  describe('Schema Updates (fromAddrs, bodyContent)', () => {
    it('should persist fromAddrs as JSON array', async () => {
      const email = createMockEmail('msg1', 'thread1', 'sender@example.com');

      (mockPrisma.gmailMessage.upsert as jest.Mock).mockResolvedValue({});

      await repository.upsert(email);

      const upsertCall = (mockPrisma.gmailMessage.upsert as jest.Mock).mock.calls[0][0];

      // Verify fromAddrs is persisted in create operation
      expect(upsertCall.create.fromAddrs).toEqual([
        {
          email: 'sender@example.com',
          name: 'Test Sender',
          raw: 'Test Sender <sender@example.com>',
        },
      ]);

      // Verify fromAddrs is persisted in update operation
      expect(upsertCall.update.fromAddrs).toEqual([
        {
          email: 'sender@example.com',
          name: 'Test Sender',
          raw: 'Test Sender <sender@example.com>',
        },
      ]);
    });

    it('should persist bodyContent field correctly', async () => {
      const emailWithPlainBody = createMockEmail('msg1', 'thread1', 'test@example.com', {
        bodyPlain: 'Test plain text body',
        bodyHtml: null,
      });

      (mockPrisma.gmailMessage.upsert as jest.Mock).mockResolvedValue({});

      await repository.upsert(emailWithPlainBody);

      const upsertCall = (mockPrisma.gmailMessage.upsert as jest.Mock).mock.calls[0][0];

      // Verify bodyContent prioritizes bodyPlain
      expect(upsertCall.create.bodyContent).toBe('Test plain text body');
      expect(upsertCall.update.bodyContent).toBe('Test plain text body');
    });

    it('should use bodyHtml when bodyPlain is not available', async () => {
      const emailWithHtmlBody = createMockEmail('msg1', 'thread1', 'test@example.com', {
        bodyPlain: null,
        bodyHtml: '<p>Test HTML body</p>',
      });

      (mockPrisma.gmailMessage.upsert as jest.Mock).mockResolvedValue({});

      await repository.upsert(emailWithHtmlBody);

      const upsertCall = (mockPrisma.gmailMessage.upsert as jest.Mock).mock.calls[0][0];

      // Verify bodyContent falls back to bodyHtml
      expect(upsertCall.create.bodyContent).toBe('<p>Test HTML body</p>');
      expect(upsertCall.update.bodyContent).toBe('<p>Test HTML body</p>');
    });

    it('should set bodyContent to null when both bodyPlain and bodyHtml are missing', async () => {
      const emailWithoutBody = createMockEmail('msg1', 'thread1', 'test@example.com', {
        bodyPlain: null,
        bodyHtml: null,
      });

      (mockPrisma.gmailMessage.upsert as jest.Mock).mockResolvedValue({});

      await repository.upsert(emailWithoutBody);

      const upsertCall = (mockPrisma.gmailMessage.upsert as jest.Mock).mock.calls[0][0];

      // Verify bodyContent is null when no body available
      expect(upsertCall.create.bodyContent).toBeNull();
      expect(upsertCall.update.bodyContent).toBeNull();
    });

    it('should handle replyToAddrs as undefined when empty', async () => {
      const email = createMockEmail('msg1', 'thread1', 'test@example.com', {
        replyTo: undefined,
      });

      (mockPrisma.gmailMessage.upsert as jest.Mock).mockResolvedValue({});

      await repository.upsert(email);

      const upsertCall = (mockPrisma.gmailMessage.upsert as jest.Mock).mock.calls[0][0];

      // Verify replyToAddrs is undefined (not null) when empty
      expect(upsertCall.create.replyToAddrs).toBeUndefined();
      expect(upsertCall.update.replyToAddrs).toBeUndefined();
    });

    it('should handle replyToAddrs when present', async () => {
      const replyToAddrs: EmailAddress[] = [
        {
          email: 'replyto@example.com',
          name: 'Reply Address',
          raw: 'Reply Address <replyto@example.com>',
        },
      ];

      const email = createMockEmail('msg1', 'thread1', 'test@example.com', {
        replyTo: replyToAddrs,
      });

      (mockPrisma.gmailMessage.upsert as jest.Mock).mockResolvedValue({});

      await repository.upsert(email);

      const upsertCall = (mockPrisma.gmailMessage.upsert as jest.Mock).mock.calls[0][0];

      // Verify replyToAddrs is persisted correctly
      expect(upsertCall.create.replyToAddrs).toEqual([
        {
          email: 'replyto@example.com',
          name: 'Reply Address',
          raw: 'Reply Address <replyto@example.com>',
        },
      ]);
    });

    it('should persist all new fields in batch insert', async () => {
      const emails: EmailMessage[] = [
        createMockEmail('msg1', 'thread1', 'sender1@example.com', {
          bodyPlain: 'Plain body 1',
        }),
        createMockEmail('msg2', 'thread2', 'sender2@example.com', {
          bodyHtml: '<p>HTML body 2</p>',
          bodyPlain: null,
        }),
      ];

      (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
        return Promise.all(operations.map(() => Promise.resolve()));
      });

      await repository.batchInsert(emails);

      // Verify transaction was called
      expect(mockPrisma.$transaction).toHaveBeenCalledTimes(1);

      // All emails should have been processed with correct field mapping
      const transactionCalls = (mockPrisma.$transaction as jest.Mock).mock.calls[0][0];
      expect(transactionCalls).toHaveLength(2);
    });
  });

  describe('close', () => {
    it('should not close Prisma client when using provided instance', async () => {
      // Repository was created with provided mockPrisma
      await repository.close();

      // Should not disconnect externally provided client
      expect(mockPrisma.$disconnect).not.toHaveBeenCalled();
    });

    it('should close Prisma client when using default instance', async () => {
      // Create repository without providing Prisma client
      const defaultRepo = new EmailRepository();
      const internalPrisma = (defaultRepo as unknown as { prisma: PrismaClient }).prisma;

      // Mock the disconnect method
      internalPrisma.$disconnect = jest.fn().mockResolvedValue(undefined);

      await defaultRepo.close();

      // Should disconnect default client
      expect(internalPrisma.$disconnect).toHaveBeenCalled();
    });
  });
});

