        createMockEmail('msg1', 'thread1', 'test1@example.com'),
        createMockEmail('msg2', 'thread2', 'test2@example.com'),
      ];

      // Mock transaction to execute all operations
      (mockPrisma.$transaction as jest.Mock).mockImplementation((operations) => {
        return Promise.all(operations.map(() => Promise.resolve()));
      });

      await repository.batchInsert(emails);

      // Verify transaction was called once
      expect(mockPrisma.$transaction).toHaveBeenCalledTimes(1);
      // Verify it was called with an array of operations
      const call = (mockPrisma.$transaction as jest.Mock).mock.calls[0][0];
      expect(Array.isArray(call)).toBe(true);
      expect(call.length).toBe(2);
    });

    it('should handle empty email array gracefully', async () => {
      await repository.batchInsert([]);

      // Should not attempt transaction
      expect(mockPrisma.$transaction).not.toHaveBeenCalled();
    });

    it('should throw error on transaction failure', async () => {
      const emails: EmailMessage[] = [createMockEmail('msg1', 'thread1', 'test@example.com')];

      (mockPrisma.$transaction as jest.Mock).mockRejectedValue(new Error('Database error'));

      await expect(repository.batchInsert(emails)).rejects.toThrow('Failed to batch insert 1 emails');
    });
  });

  describe('batchUpdateMetadata', () => {
